import{_ as i,c as o,a0 as a,o as l}from"./chunks/framework.B6JXc2q-.js";const _=JSON.parse('{"title":"认证运行时恢复规范","description":"","frontmatter":{},"headers":[],"relativePath":"spec/auth_runtime_recovery.md","filePath":"spec/auth_runtime_recovery.md"}'),c={name:"spec/auth_runtime_recovery.md"};function d(r,e,t,u,n,h){return l(),o("div",null,e[0]||(e[0]=[a('<h1 id="认证运行时恢复规范" tabindex="-1">认证运行时恢复规范 <a class="header-anchor" href="#认证运行时恢复规范" aria-label="Permalink to &quot;认证运行时恢复规范&quot;">​</a></h1><blockquote><p>最后更新：2026-03-12</p></blockquote><h2 id="_1-背景" tabindex="-1">1. 背景 <a class="header-anchor" href="#_1-背景" aria-label="Permalink to &quot;1. 背景&quot;">​</a></h2><p><code>xiaomusic-core</code> 早期曾把两类不同动作混在一条链路里：</p><ul><li>向 Xiaomi 云端发起会话 refresh</li><li>从本地 <code>auth.json</code> 重载运行时认证状态</li></ul><p>在生产环境中，自动调用 <code>mi_account.login(&quot;micoapi&quot;)</code> 经常触发 Xiaomi 风控（如 <code>70016</code>），无法稳定写回新的短期会话字段，导致自动恢复链不确定、故障被放大。</p><p>因此当前主线将认证恢复链收口为可预测、可观测、可审计的固定流程。</p><h2 id="_2-三层认证模型" tabindex="-1">2. 三层认证模型 <a class="header-anchor" href="#_2-三层认证模型" aria-label="Permalink to &quot;2. 三层认证模型&quot;">​</a></h2><ul><li>长期认证状态（持久化）：<code>passToken</code>、<code>psecurity</code>、<code>ssecurity</code>、<code>userId</code>、<code>cUserId</code>、<code>deviceId</code></li><li>短期会话状态（持久化）：<code>serviceToken</code>、<code>yetAnotherServiceToken</code></li><li>运行时状态（内存）：<code>MiAccount</code> seed、<code>mina_service</code>、<code>miio_service</code>、device map</li></ul><p>系统始终以 <code>auth.json</code> / <code>TokenStore</code> 为事实来源。</p><h2 id="_3-为什么自动登录-fallback-被禁用" tabindex="-1">3. 为什么自动登录 fallback 被禁用 <a class="header-anchor" href="#_3-为什么自动登录-fallback-被禁用" aria-label="Permalink to &quot;3. 为什么自动登录 fallback 被禁用&quot;">​</a></h2><ul><li>服务端自动调用 <code>mi_account.login(&quot;micoapi&quot;)</code> 在恢复窗口中不稳定。</li><li>常见失败表现为 Xiaomi 返回 <code>70016</code>，且没有新的短期 token 被成功写回。</li><li>因此这条路径被策略性禁用，不再作为自动恢复主链。</li><li>如果命中该分支，日志必须显式记录 <code>disabled_by_policy=true</code>。</li></ul><h2 id="_4-标准恢复链" tabindex="-1">4. 标准恢复链 <a class="header-anchor" href="#_4-标准恢复链" aria-label="Permalink to &quot;4. 标准恢复链&quot;">​</a></h2><h3 id="_4-1-短期会话失效的自动恢复" tabindex="-1">4.1 短期会话失效的自动恢复 <a class="header-anchor" href="#_4-1-短期会话失效的自动恢复" aria-label="Permalink to &quot;4.1 短期会话失效的自动恢复&quot;">​</a></h3><p>唯一允许的顺序：</p><ol><li>清理短期会话（<code>serviceToken</code>、<code>yetAnotherServiceToken</code>）</li><li>基于长期认证材料重建短期会话</li><li>执行 runtime rebind（<code>mina_service</code>、<code>miio_service</code>）</li><li>执行 verify（<code>device_list</code> / <code>runtime_auth_ready</code>）</li></ol><p>不允许存在隐式替代分支。</p><h3 id="_4-2-扫码登录后的手动恢复" tabindex="-1">4.2 扫码登录后的手动恢复 <a class="header-anchor" href="#_4-2-扫码登录后的手动恢复" aria-label="Permalink to &quot;4.2 扫码登录后的手动恢复&quot;">​</a></h3><p>当用户完成扫码登录且新的短期 token 已持久化到磁盘时：</p><ol><li>若运行时仍未 ready，系统会自动调度一次 runtime reload</li><li>也可以调用 <code>POST /api/auth/refresh</code> 或 <code>POST /api/auth/refresh_runtime</code></li><li>从磁盘重载运行时认证状态</li><li>执行 runtime rebind</li><li>刷新 device map</li><li>执行 verify</li></ol><p>这一过程不需要重启容器，自动触发与手动触发共享同一核心链路。</p><h2 id="_5-refresh-与-reload-runtime-的区别" tabindex="-1">5. Refresh 与 Reload Runtime 的区别 <a class="header-anchor" href="#_5-refresh-与-reload-runtime-的区别" aria-label="Permalink to &quot;5. Refresh 与 Reload Runtime 的区别&quot;">​</a></h2><ul><li>Refresh：云端会话刷新动作</li><li>Refresh runtime：从本地磁盘重载运行时认证状态，不依赖云端 refresh 成功</li></ul><p>当前主线语义：</p><ul><li><code>POST /api/auth/refresh</code> 表示手动刷新运行时</li><li><code>POST /api/auth/refresh_runtime</code> 是同语义的显式别名</li><li>自动 runtime reload 由 <code>init_all_data()</code> / <code>keepalive_loop()</code> 受控触发，不是新的执行链</li></ul><h2 id="_6-locked-策略" tabindex="-1">6. Locked 策略 <a class="header-anchor" href="#_6-locked-策略" aria-label="Permalink to &quot;6. Locked 策略&quot;">​</a></h2><p><code>auth locked</code> 是终态保护状态，只应在长期认证材料缺失或等价硬故障时触发。</p><p>以下情况不应直接进入 locked：</p><ul><li>短期会话失效</li><li>被策略禁用的自动登录 fallback</li><li>单次 runtime verify 失败</li></ul><h2 id="_7-可观测性" tabindex="-1">7. 可观测性 <a class="header-anchor" href="#_7-可观测性" aria-label="Permalink to &quot;7. 可观测性&quot;">​</a></h2><p>运行时重载会输出结构化事件 <code>auth_runtime_reload</code>，至少包含：</p><ul><li><code>stage=reload_runtime</code></li><li><code>result</code></li><li><code>token_store_reloaded</code></li><li><code>disk_has_serviceToken</code></li><li><code>disk_has_yetAnotherServiceToken</code></li><li><code>runtime_seed_has_serviceToken</code></li><li><code>mina_service_rebuilt</code></li><li><code>miio_service_rebuilt</code></li><li><code>device_map_refreshed</code></li><li><code>verify_result</code></li><li><code>error_code</code></li><li><code>error_message</code></li><li><code>refresh_token_path_invoked</code></li></ul><p>相关调试接口：</p><ul><li><code>GET /api/v1/debug/auth_state</code></li><li><code>GET /api/v1/debug/auth_recovery_state</code></li><li><code>GET /api/v1/debug/miaccount_login_trace</code></li><li><code>GET /api/v1/debug/auth_runtime_reload_state</code></li></ul><h2 id="_8-运维建议" tabindex="-1">8. 运维建议 <a class="header-anchor" href="#_8-运维建议" aria-label="Permalink to &quot;8. 运维建议&quot;">​</a></h2><ul><li>保持网络链路稳定、低抖动</li><li>避免对 Xiaomi 认证流量做不必要的代理或协议改写</li><li>将 <code>auth.json</code> 视为事实来源；扫码登录后应从磁盘重建 runtime，而不是依赖容器内旧内存态</li></ul><h2 id="_9-已知边界" tabindex="-1">9. 已知边界 <a class="header-anchor" href="#_9-已知边界" aria-label="Permalink to &quot;9. 已知边界&quot;">​</a></h2><ul><li>Xiaomi 服务端风控无法被彻底消除</li><li>系统目标不是“零失败”，而是“低频失败、可恢复、可预测”</li><li>playlist / queue / library / object 等 API 扩展不在当前稳定版收口范围内</li></ul>',38)]))}const m=i(c,[["render",d]]);export{_ as __pageData,m as default};
